<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand Sandbox</title>
<style>
  :root {
    --bg: #121218;
    --panel: #1c1c26;
    --border: #2e2e3a;
    --accent: #7dd3fc;
    --text: #e5e5ea;
  }
  * { box-sizing: border-box; }
  html, body {
    margin: 0;
    height: 100%;
    background: var(--bg);
    color: var(--text);
    font-family: -apple-system, "Segoe UI", Roboto, sans-serif;
    display: flex;
    align-items: center;
    justify-content: center;
  }
  #app {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 14px;
    padding: 24px;
  }
  h1 {
    font-size: 18px;
    font-weight: 600;
    letter-spacing: 0.5px;
    margin: 0;
    color: var(--accent);
  }
  #canvas-wrap {
    border: 2px solid var(--border);
    border-radius: 8px;
    overflow: hidden;
    box-shadow: 0 8px 30px rgba(0,0,0,0.5);
    background: #000;
    line-height: 0;
  }
  #sand {
    display: block;
    width: 500px;
    height: 500px;
    cursor: crosshair;
    image-rendering: pixelated;
  }
  #controls {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    justify-content: center;
    max-width: 520px;
  }
  button.mat-btn {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 14px;
    background: var(--panel);
    border: 1px solid var(--border);
    border-radius: 6px;
    color: var(--text);
    font-size: 13px;
    cursor: pointer;
    transition: background 0.15s, border-color 0.15s, transform 0.05s;
  }
  button.mat-btn:hover {
    border-color: var(--accent);
  }
  button.mat-btn:active {
    transform: scale(0.96);
  }
  button.mat-btn.active {
    background: #26263a;
    border-color: var(--accent);
    box-shadow: 0 0 0 1px var(--accent) inset;
  }
  .swatch {
    width: 14px;
    height: 14px;
    border-radius: 3px;
    display: inline-block;
    border: 1px solid rgba(255,255,255,0.15);
  }
  #clear {
    padding: 8px 18px;
    background: #3a1e22;
    border: 1px solid #5a2a30;
    color: #ffb4b4;
    border-radius: 6px;
    font-size: 13px;
    cursor: pointer;
    transition: background 0.15s;
  }
  #clear:hover {
    background: #4a2428;
  }
  #hint {
    font-size: 12px;
    color: #8a8a98;
  }
</style>
</head>
<body>
<div id="app">
  <h1>Falling Sand Sandbox</h1>
  <div id="canvas-wrap">
    <canvas id="sand" width="500" height="500"></canvas>
  </div>
  <div id="controls">
    <button class="mat-btn active" id="mat-sand" data-mat="sand"><span class="swatch" style="background:#d9c27e"></span>Sand</button>
    <button class="mat-btn" id="mat-water" data-mat="water"><span class="swatch" style="background:#3aa0ff"></span>Water</button>
    <button class="mat-btn" id="mat-wall" data-mat="wall"><span class="swatch" style="background:#7a7a86"></span>Wall</button>
    <button class="mat-btn" id="mat-acid" data-mat="acid"><span class="swatch" style="background:#8ef23f"></span>Acid</button>
    <button class="mat-btn" id="mat-empty" data-mat="empty"><span class="swatch" style="background:#000"></span>Eraser</button>
    <button id="clear">Clear</button>
  </div>
  <div id="hint">Click and drag on the canvas to paint. Pick a material above.</div>
</div>

<script>
(function () {
  "use strict";

  const W = 100, H = 100; // grid cells (>= 80x80)
  const canvas = document.getElementById('sand');
  const ctx = canvas.getContext('2d');
  const cssW = canvas.clientWidth || 500;
  const cssH = canvas.clientHeight || 500;
  const cellW = canvas.width / W;
  const cellH = canvas.height / H;

  const EMPTY = 'empty', SAND = 'sand', WATER = 'water', WALL = 'wall', ACID = 'acid';
  const COLORS = {
    empty: '#0a0a0e',
    sand: '#d9c27e',
    water: '#3aa0ff',
    wall: '#7a7a86',
    acid: '#8ef23f'
  };

  let grid = new Array(W * H).fill(EMPTY);
  let moved = new Uint8Array(W * H);

  function xy(x, y) { return y * W + x; }
  function inBounds(x, y) { return x >= 0 && x < W && y >= 0 && y < H; }

  function swapCells(a, b) {
    const tmp = grid[a];
    grid[a] = grid[b];
    grid[b] = tmp;
    moved[a] = 1;
    moved[b] = 1;
  }

  function stepSand(x, y) {
    const idx = xy(x, y);
    if (y === H - 1) return; // bottom boundary is solid
    const below = xy(x, y + 1);
    if (!moved[below]) {
      const belowMat = grid[below];
      if (belowMat === EMPTY || belowMat === WATER || belowMat === ACID) {
        swapCells(idx, below);
        return;
      }
    }
    const dirs = Math.random() < 0.5 ? [-1, 1] : [1, -1];
    for (const d of dirs) {
      const nx = x + d;
      if (nx < 0 || nx >= W) continue;
      const nidx = xy(nx, y + 1);
      if (moved[nidx]) continue;
      const nmat = grid[nidx];
      if (nmat === EMPTY || nmat === WATER || nmat === ACID) {
        swapCells(idx, nidx);
        return;
      }
    }
  }

  function stepLiquidMove(x, y) {
    const idx = xy(x, y);
    if (y < H - 1) {
      const below = xy(x, y + 1);
      if (!moved[below] && grid[below] === EMPTY) {
        swapCells(idx, below);
        return true;
      }
      const dirsDiag = Math.random() < 0.5 ? [-1, 1] : [1, -1];
      for (const d of dirsDiag) {
        const nx = x + d;
        if (nx < 0 || nx >= W) continue;
        const nidx = xy(nx, y + 1);
        if (!moved[nidx] && grid[nidx] === EMPTY) {
          swapCells(idx, nidx);
          return true;
        }
      }
    }
    const dirs = Math.random() < 0.5 ? [-1, 1] : [1, -1];
    for (const d of dirs) {
      const nx = x + d;
      if (nx < 0 || nx >= W) continue;
      const nidx = xy(nx, y);
      if (!moved[nidx] && grid[nidx] === EMPTY) {
        swapCells(idx, nidx);
        return true;
      }
    }
    return false;
  }

  function stepAcid(x, y) {
    const idx = xy(x, y);
    const candidates = [];
    if (y + 1 < H) candidates.push(xy(x, y + 1));
    const dirs = Math.random() < 0.5 ? [-1, 1] : [1, -1];
    for (const d of dirs) {
      const nx = x + d;
      if (nx >= 0 && nx < W) candidates.push(xy(nx, y));
    }
    for (const t of candidates) {
      if (moved[t]) continue;
      const tmat = grid[t];
      if (tmat === SAND || tmat === WALL) {
        grid[t] = EMPTY;
        grid[idx] = EMPTY;
        moved[idx] = 1;
        moved[t] = 1;
        return;
      }
    }
    stepLiquidMove(x, y);
  }

  function simulateStep() {
    moved.fill(0);
    for (let y = H - 1; y >= 0; y--) {
      const leftToRight = Math.random() < 0.5;
      for (let i = 0; i < W; i++) {
        const x = leftToRight ? i : (W - 1 - i);
        const idx = xy(x, y);
        if (moved[idx]) continue;
        const mat = grid[idx];
        if (mat === EMPTY || mat === WALL) continue;
        if (mat === SAND) stepSand(x, y);
        else if (mat === WATER) stepLiquidMove(x, y);
        else if (mat === ACID) stepAcid(x, y);
      }
    }
  }

  function render() {
    ctx.fillStyle = COLORS.empty;
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        const mat = grid[xy(x, y)];
        if (mat === EMPTY) continue;
        ctx.fillStyle = COLORS[mat];
        ctx.fillRect(x * cellW, y * cellH, cellW, cellH);
      }
    }
  }

  // ---- Public API ----
  window.sim = {
    w: W,
    h: H,
    tick: function (n) {
      n = n || 1;
      for (let i = 0; i < n; i++) simulateStep();
      render();
    },
    get: function (x, y) {
      if (!inBounds(x, y)) return EMPTY;
      return grid[xy(x, y)];
    },
    set: function (x, y, material) {
      if (!inBounds(x, y)) return;
      if (![EMPTY, SAND, WATER, WALL, ACID].includes(material)) return;
      grid[xy(x, y)] = material;
      render();
    },
    clear: function () {
      grid.fill(EMPTY);
      render();
    }
  };

  // ---- UI wiring ----
  let currentMaterial = SAND;
  const matButtons = document.querySelectorAll('.mat-btn');
  matButtons.forEach(btn => {
    btn.addEventListener('click', () => {
      currentMaterial = btn.dataset.mat;
      matButtons.forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
    });
  });

  document.getElementById('clear').addEventListener('click', () => {
    window.sim.clear();
  });

  let painting = false;

  function paintAt(clientX, clientY) {
    const rect = canvas.getBoundingClientRect();
    const relX = (clientX - rect.left) / rect.width;
    const relY = (clientY - rect.top) / rect.height;
    const gx = Math.floor(relX * W);
    const gy = Math.floor(relY * H);
    const radius = 1;
    for (let dy = -radius; dy <= radius; dy++) {
      for (let dx = -radius; dx <= radius; dx++) {
        const x = gx + dx, y = gy + dy;
        if (inBounds(x, y)) grid[xy(x, y)] = currentMaterial;
      }
    }
  }

  canvas.addEventListener('mousedown', (e) => {
    painting = true;
    paintAt(e.clientX, e.clientY);
    render();
  });
  window.addEventListener('mouseup', () => { painting = false; });
  canvas.addEventListener('mousemove', (e) => {
    if (!painting) return;
    paintAt(e.clientX, e.clientY);
    render();
  });
  canvas.addEventListener('mouseleave', () => {
    // keep painting state; user might drag back in
  });

  // touch support
  canvas.addEventListener('touchstart', (e) => {
    painting = true;
    const t = e.touches[0];
    paintAt(t.clientX, t.clientY);
    render();
    e.preventDefault();
  }, { passive: false });
  canvas.addEventListener('touchmove', (e) => {
    if (!painting) return;
    const t = e.touches[0];
    paintAt(t.clientX, t.clientY);
    render();
    e.preventDefault();
  }, { passive: false });
  canvas.addEventListener('touchend', () => { painting = false; });

  // ---- Animation loop ----
  let lastStep = 0;
  const stepInterval = 1000 / 30; // 30 sim steps/sec

  function loop(ts) {
    if (ts - lastStep >= stepInterval) {
      simulateStep();
      render();
      lastStep = ts;
    }
    requestAnimationFrame(loop);
  }

  render();
  requestAnimationFrame(loop);
})();
</script>
</body>
</html>
